import{_ as a,o as s,c as i,a3 as e}from"./chunks/framework.Daqi0Atb.js";const n="/assets/10-02.BT5Jsjx7.png",d="/assets/10-01.CDbg8C8A.png",u=JSON.parse('{"title":"10｜多模态融合：日志、SQL 和 PDF 一起进 Agent","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/10-多模态融合：日志、SQL 和 PDF 一起进 Agent.md","filePath":"courses/agent-design/10-多模态融合：日志、SQL 和 PDF 一起进 Agent.md"}'),r={name:"courses/agent-design/10-多模态融合：日志、SQL 和 PDF 一起进 Agent.md"};function o(h,t,l,p,g,k){return s(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="_10-多模态融合-日志、sql-和-pdf-一起进-agent" tabindex="-1">10｜多模态融合：日志、SQL 和 PDF 一起进 Agent <a class="header-anchor" href="#_10-多模态融合-日志、sql-和-pdf-一起进-agent" aria-label="Permalink to &quot;10｜多模态融合：日志、SQL 和 PDF 一起进 Agent&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><p>感知模块最后一讲：不同形态的数据（文本、表格、图片、PDF、日志、音频）进入 Agent 前，先要变成最适合模型消化的形态——这就是<strong>多模态融合（Multi-Modal Fusion）</strong>。</p><hr><h2 id="感知-×-并行-多模态融合在双轴图谱的位置" tabindex="-1">感知 × 并行：多模态融合在双轴图谱的位置 <a class="header-anchor" href="#感知-×-并行-多模态融合在双轴图谱的位置" aria-label="Permalink to &quot;感知 × 并行：多模态融合在双轴图谱的位置&quot;">​</a></h2><p><img src="'+n+'" alt="多模态融合在双轴矩阵的位置：感知×并行"></p><ul><li><strong>认知功能</strong>：感知 — 决定 Agent 最终看到什么</li><li><strong>执行拓扑</strong>：并行 — 多种异构数据源同时进入，每种走最适合自己的处理路径</li></ul><p><strong>和前三个感知模式的本质区别</strong>：</p><table tabindex="0"><thead><tr><th>模式</th><th>解决的问题</th></tr></thead><tbody><tr><td>上下文分诊</td><td>哪些 token 进来</td></tr><tr><td>语义压缩</td><td>进来以后怎么压</td></tr><tr><td>渐进发现</td><td>不知道在哪的信息怎么找</td></tr><tr><td><strong>多模态融合</strong></td><td><strong>数据在进入 Agent 之前，应该先变成什么形态</strong></td></tr></tbody></table><p>形态一开始就错了，后面如何分诊、压缩、探索，都是在错误材料上继续消耗。</p><hr><h2 id="核心决策卡-图保留还是转文本" tabindex="-1">核心决策卡：图保留还是转文本？ <a class="header-anchor" href="#核心决策卡-图保留还是转文本" aria-label="Permalink to &quot;核心决策卡：图保留还是转文本？&quot;">​</a></h2><p><strong>判断标准</strong>：这份材料的价值，藏在<strong>布局</strong>里，还是<strong>文字和结构</strong>里？</p><ul><li>价值在布局、箭头、位置关系里 → <strong>保留为图</strong></li><li>价值在文字、数字、表格结构里 → <strong>转 Markdown / Mermaid / CSV / JSON</strong></li></ul><table tabindex="0"><thead><tr><th>输入类型</th><th>推荐处理</th><th>原因</th></tr></thead><tbody><tr><td>架构图 / 流程图</td><td>能转 Mermaid 就转 Mermaid</td><td>几十 token vs 几百 KB XML，空间关系 Mermaid 表达清楚</td></tr><tr><td>表格 / 电子表格</td><td>默认转 Markdown</td><td>核心价值在行列字段，不在截图</td></tr><tr><td>跨页表、多层表头、合并单元格</td><td>保留为图</td><td>转 Markdown 会丢结构</td></tr><tr><td>图表 / 热力图</td><td>保留图 + 数字抽成 CSV/JSON</td><td>趋势看图，精确数字要靠结构化数据算</td></tr><tr><td>密集文字截图</td><td>压到合适尺寸直接交 vision</td><td>OCR 太长还有格式噪声</td></tr></tbody></table><hr><h2 id="claude-vision-api-的-token-数学" tabindex="-1">Claude Vision API 的 Token 数学 <a class="header-anchor" href="#claude-vision-api-的-token-数学" aria-label="Permalink to &quot;Claude Vision API 的 Token 数学&quot;">​</a></h2><p>图片 token 估算公式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tokens = width × height / 750</span></span></code></pre></div><p>一张 1024×1024 图 ≈ 1400 token ≈ 1.5 倍同长度中文文本。</p><p><strong>直觉反差</strong>：图片并没有想象中那么贵。一张完整架构图如果强行转文字要 800-1200 字，保留为图反而更划算。</p><p><strong>PDF 的问题</strong>：30 页文本密集型 PDF ≈ 5-6 万 token。80 页研报暴力喂入轻松超 15 万 token。</p><p><strong>提示词缓存</strong>（prompt caching）：同一份文件被多次问答时，把可复用内容放进 cache，可能直接改变 Agent 的经济模型。</p><hr><h2 id="日志处理的正确姿势" tabindex="-1">日志处理的正确姿势 <a class="header-anchor" href="#日志处理的正确姿势" aria-label="Permalink to &quot;日志处理的正确姿势&quot;">​</a></h2><p><strong>错误做法</strong>：长日志直接进主上下文</p><p><strong>正确流水线</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash_filter（预过滤）→ log_subagent（提炼结构化摘要）→ structured summary → 主 Agent</span></span></code></pre></div><p>bash_filter 压缩比健康区间：<strong>0.01-0.05</strong>（500MB 日志压到 5-25MB）</p><hr><h2 id="lazy-import-原则" tabindex="-1">Lazy Import 原则 <a class="header-anchor" href="#lazy-import-原则" aria-label="Permalink to &quot;Lazy Import 原则&quot;">​</a></h2><p>音频、vision、PDF 解析等依赖，<strong>不要在 module 顶层 import</strong>，要延迟到函数内部。80% 用户用不到，但写在 import 顶层的库会导致 Agent 在 Docker/CI/SSH 环境里启动就崩。</p><hr><h2 id="金融研报分析-agent-流水线" tabindex="-1">金融研报分析 Agent 流水线 <a class="header-anchor" href="#金融研报分析-agent-流水线" aria-label="Permalink to &quot;金融研报分析 Agent 流水线&quot;">​</a></h2><p><img src="'+d+`" alt="金融研报多模态融合流水线"></p><h3 id="三步走" tabindex="-1">三步走 <a class="header-anchor" href="#三步走" aria-label="Permalink to &quot;三步走&quot;">​</a></h3><p><strong>步骤一：融合层分发</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>处理方式</th><th>Token 估算</th></tr></thead><tbody><tr><td>PDF 主体</td><td>TOC + 关键页（3页 × 2K）</td><td>~6K</td></tr><tr><td>关键图表（5张）</td><td>保留为图</td><td>~7K</td></tr><tr><td>表格（12张）</td><td>转 Markdown</td><td>~2.4K</td></tr><tr><td>装饰图</td><td>直接丢弃</td><td>0</td></tr></tbody></table><p><strong>总产出约 16K vs 暴力全喂 90K</strong></p><p><strong>步骤二：三任务并行</strong></p><ul><li>摘要任务：800 字核心论点</li><li>数字核查：每条数字结论必须带 page/chart 引用</li><li>销售要点：5-7 条受众定制话术</li></ul><p><strong>关键图表识别规则</strong>（行业知识，不是普通配置）：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pattern_keywords </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;市场规模&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;市占率&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;增长趋势&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;营收&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;利润率&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;毛利率&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ROE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;渗透率&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;用户数&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ARPU&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;估值&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PB&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PS&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>步骤三：结果合并 + FusionTrace</strong></p><p>FusionTrace 记录：保留了多少张关键图、几张表转了 Markdown、几张装饰图丢弃、总消耗多少 token。质量审查有依据。</p><hr><h2 id="三个可观测指标" tabindex="-1">三个可观测指标 <a class="header-anchor" href="#三个可观测指标" aria-label="Permalink to &quot;三个可观测指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>健康区间</th><th>异常信号</th></tr></thead><tbody><tr><td><code>token_distribution_by_modality</code></td><td>text 40-60% / image 10-30% / table 10-20%</td><td>image 突然 60% → 该转的图没转</td></tr><tr><td><code>fusion_processing_p99_ms</code></td><td>&lt; 5 秒</td><td>飙到 30 秒 → PDF 抽取或 OCR 卡住</td></tr><tr><td><code>bash_filter_compression_ratio</code></td><td>0.01-0.05</td><td>&gt; 0.1 → 过滤太松；&lt; 0.005 → 过滤太狠丢信号</td></tr></tbody></table><hr><h2 id="三类多模态事故" tabindex="-1">三类多模态事故 <a class="header-anchor" href="#三类多模态事故" aria-label="Permalink to &quot;三类多模态事故&quot;">​</a></h2><ol><li><strong>看错图</strong>：5800 亿报成 5800 万 — 图表帮助定位趋势，精确数字要落到结构化数据</li><li><strong>图片账单爆炸</strong>：Agent loop 每轮重复打包同一张图 — 用缩略图 + 提示缓存</li><li><strong>Sub-Agent 关键发现丢失</strong>：每次传整段上下文没预算上限 — 关键结论进状态存储，上下文只传指针</li></ol><hr><h2 id="感知模块收束" tabindex="-1">感知模块收束 <a class="header-anchor" href="#感知模块收束" aria-label="Permalink to &quot;感知模块收束&quot;">​</a></h2><p>四个感知模式的顺序很重要：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>多模态融合（最前）→ 上下文分诊 → 语义压缩 → 渐进发现（最后）</span></span></code></pre></div><p>形态一开始就错了，后面全是徒劳。</p><blockquote><p>感知模块管的是：<strong>当前会话内 Agent 看见什么</strong>。会话结束，这些上下文全部回收。下一模块进入记忆：怎么把这次学到的东西跨会话留下来。</p></blockquote><hr><h2 id="关键对话总结" tabindex="-1">关键对话总结 <a class="header-anchor" href="#关键对话总结" aria-label="Permalink to &quot;关键对话总结&quot;">​</a></h2><h3 id="_1-核心决策卡-图保留还是转文本" tabindex="-1">1. 核心决策卡：图保留还是转文本？ <a class="header-anchor" href="#_1-核心决策卡-图保留还是转文本" aria-label="Permalink to &quot;1. 核心决策卡：图保留还是转文本？&quot;">​</a></h3><p><strong>判断标准</strong>：价值的载体是<strong>布局</strong>，还是<strong>文字和结构</strong>？</p><table tabindex="0"><thead><tr><th>输入类型</th><th>推荐处理</th><th>原因</th></tr></thead><tbody><tr><td>架构图 / 流程图</td><td>能转 Mermaid 就转 Mermaid</td><td>几十 token vs 几百 KB XML，空间关系 Mermaid 表达清楚</td></tr><tr><td>表格 / 电子表格</td><td>默认转 Markdown</td><td>核心价值在行列字段，不在截图</td></tr><tr><td>跨页表、多层表头、合并单元格</td><td>保留为图</td><td>转 Markdown 会丢结构</td></tr><tr><td>图表 / 热力图</td><td>保留图 + 数字抽成 CSV/JSON</td><td>趋势看图，精确数字要靠结构化数据算</td></tr><tr><td>密集文字截图</td><td>压到合适尺寸直接交 vision</td><td>OCR 太长还有格式噪声</td></tr></tbody></table><h3 id="_2-token-直觉反差" tabindex="-1">2. Token 直觉反差 <a class="header-anchor" href="#_2-token-直觉反差" aria-label="Permalink to &quot;2. Token 直觉反差&quot;">​</a></h3><p>一张 1024×1024 图 ≈ 1400 token ≈ 1.5 倍同长度中文文本。</p><p><strong>图片并没有想象中那么贵</strong>——一张完整架构图如果强行转文字要 800-1200 字，保留为图反而更划算。</p><h3 id="_3-日志处理流水线-对你最实用" tabindex="-1">3. 日志处理流水线（对你最实用） <a class="header-anchor" href="#_3-日志处理流水线-对你最实用" aria-label="Permalink to &quot;3. 日志处理流水线（对你最实用）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bash_filter（预过滤）→ log_subagent（提炼结构化摘要）→ 主 Agent</span></span></code></pre></div><p>bash_filter 压缩比健康区间：<strong>0.01-0.05</strong>（500MB 日志压到 5-25MB）</p><p>这条流水线对你的生成应用同样适用：如果 Agent 需要参考已有日志/error 输出才能做好决策，先用脚本过滤噪声，再让子 Agent 提炼摘要，最后主 Agent 只拿到精华。</p><h3 id="_4-感知模式组完整收束" tabindex="-1">4. 感知模式组完整收束 <a class="header-anchor" href="#_4-感知模式组完整收束" aria-label="Permalink to &quot;4. 感知模式组完整收束&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>多模态融合（最前）→ 上下文分诊 → 语义压缩 → 渐进发现（最后）</span></span></code></pre></div><table tabindex="0"><thead><tr><th>模式</th><th>解决的问题</th><th>拓扑</th></tr></thead><tbody><tr><td>多模态融合</td><td>数据进 Agent 前先变成最适合的形态</td><td>并行</td></tr><tr><td>上下文分诊</td><td>哪些 token 进来</td><td>路由</td></tr><tr><td>语义压缩</td><td>进来以后怎么压</td><td>链式</td></tr><tr><td>渐进发现</td><td>不知道在哪的信息怎么找</td><td>循环</td></tr></tbody></table><p><strong>形态一开始就错了，后面全是徒劳。</strong></p><h3 id="_5-一句话带走" tabindex="-1">5. 一句话带走 <a class="header-anchor" href="#_5-一句话带走" aria-label="Permalink to &quot;5. 一句话带走&quot;">​</a></h3><blockquote><p><strong>感知模块管的是当前会话内 Agent 看见什么。形态决定一切——图片转文本可能丢布局，表格塞 markdown 可能丢结构。核心判断永远只有一个：这份材料的价值，藏在布局里，还是藏在文字和结构里？</strong></p></blockquote>`,77)])])}const b=a(r,[["render",o]]);export{u as __pageData,b as default};
